// Node Code n8n - Mode: "Run Once for All Items"
// Adapter les noms de nodes ci-dessous selon votre workflow réel

// ── Source 1 : toutes les lignes ERP (BC / PORDERQ) ─
const erpItems = $('Microsoft SQL2').all(); // <-- remplacer par le vrai nom du node

// ── Source 2 : les cas non matchés (structure avec .input et .statut) ─
const allCandidats = $input.all(); // ou $('Nom du Node Matching').all()
const unmatched = allCandidats.filter(item => item.json.statut === 'non_matched');

// ── Regrouper les lignes ERP par numéro de BC ─
const bcGroups = {};
for (const item of erpItems) {
  const bc = item.json.POHNUM_0;
  if (!bc) continue;
  if (!bcGroups[bc]) bcGroups[bc] = [];
  // Éviter les doublons de lignes ERP (même ITMREF_0)
  const alreadyIn = bcGroups[bc].some(r => r.ITMREF_0 === item.json.ITMREF_0);
  if (!alreadyIn) bcGroups[bc].push(item.json);
}

// ── Construire un item par cas non résolu avec toutes les lignes ERP dispo ─
const toProcess = unmatched.map(item => {
  const data = item.json.input; // les données OCR sont imbriquées ici
  const bc   = data.POHNUM_0;
  const erpLines = bcGroups[bc] || [];

  return {
    json: {
      // Données OCR du cas non résolu
      designation_ocr:   data.designation_ocr,
      reference_ocr:      data.reference_ocr,
      montant_ht_ocr:     data.montant_ht_ocr,
      quantite_ocr:       data.quantite_ocr,
      prix_unitaire_ocr:  data.prix_unitaire_ocr,
      numero_bl:          data.numero_bl,
      date_bc:            data.ORDDAT_0,
      code_fournisseur:   data.BPSNUM_0,
      numero_bc:          bc,

      // Score / contexte (adapté aux nouveaux noms de champs)
      _statut_initial:    item.json.statut,
      _score_initial:     item.json.score,
      _skip_reason:       data.skip_numerique_reason,
      _nb_bc_candidats:   item.json.nb_bc_candidats,
      _bc_candidats:      item.json.bc_candidats,

      // Toutes les lignes ERP disponibles pour ce BC (pour le prompt Claude)
      erp_candidates: JSON.stringify(
        erpLines.map(r => ({
          code_article: r.ITMREF_0,
          designation:  r.ITMDES1_0,
          quantite:     r.Quantite,
          montant_ht:   r.montant_ht
        }))
      )
    }
  };
});

return toProcess;

const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.text || item.json.output || item.json.content || '';

  let parsed = null;

  // ── Tentative 1 : extraire tableau JSON depuis ```json ... ``` ──
  const fenceMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
  if (fenceMatch) {
    try { parsed = JSON.parse(fenceMatch[1]); } catch (e) { parsed = null; }
  }

  // ── Tentative 2 : extraire tableau brut [ ... ] ──────────────
  if (!parsed) {
    const bracketMatch = text.match(/\[[\s\S]*\]/);
    if (bracketMatch) {
      try { parsed = JSON.parse(bracketMatch[0]); } catch (e) { parsed = null; }
    }
  }

  // ── Échec total ───────────────────────────────────────────────
  if (!parsed || !Array.isArray(parsed)) {
    results.push({
      json: {
        _parse_error:   true,
        _raw_text:      text,
        _alerte:        'Impossible de parser la réponse LLM',
        match_confirme: false
      }
    });
    continue;
  }

  // ── Aplatir chaque objet du tableau ──────────────────────────
  for (const entry of parsed) {
    const bl       = entry.bl       || {};
    const matching = entry.matching || {};

    results.push({
      json: {
        // BL
        numero_bl:                bl.numero_bl   || '',
        date_bc:                  bl.date_bc     || '',
        numero_bc:                bl.numero_bc   || '',
        code_fournisseur:         entry.code_fournisseur || '',
        quantite_ocr:             entry.quantite_ocr || '',
        marque:                   entry.marque || '',

        // Matching principal
        designation_ocr:          matching.designation_ocr  || '',
        designation_erp:          matching.designation_erp  || '',
        code_article_erp:         matching.code_article_erp || '',

        // Résultat final
        match_confirme:           matching.match_confirme   ?? false,
        niveau_confiance:         matching.niveau_confiance || '',
        alerte:                   matching.alerte           || '',
        justification_globale:    matching.justification_globale || '',

        // Analyse sémantique
        semantique_candidat:      matching.analyse_semantique?.meilleur_candidat     || '',
        semantique_score:         matching.analyse_semantique?.evaluation_candidates?.[0]?.score_semantique ?? null,
        semantique_justification: matching.analyse_semantique?.justification_choix   || '',
        semantique_decomposition: matching.analyse_semantique?.decomposition_ocr     || [],

        // JSON complet pour audit
        _raw_json: entry
      }
    });
  }
}

return results;

const items = $input.all();

// Récupérer le tableau data du premier item
const dataArray = items[0].json.data || [];

// Construire le prompt avec les vraies données sérialisées
const articlesJson = JSON.stringify(dataArray, null, 2);
const nbArticles   = dataArray.length;

// Construire un résumé lisible article par article pour le prompt
const articlesReadable = dataArray.map((article, index) => {
  const candidates = JSON.parse(article.erp_candidates || '[]');
  const candidatesReadable = candidates.map(c =>
    `      · [${c.code_article}] ${c.designation} | Qté: ${c.quantite} | Montant HT: ${c.montant_ht}`
  ).join('\n');

  return `ARTICLE ${index + 1} :
  - designation_ocr   : ${article.designation_ocr}
  - montant_ht_ocr    : ${article.montant_ht_ocr}
  - quantite_ocr      : ${article.quantite_ocr}
  - numero_bl         : ${article.numero_bl}
  - date_bc           : ${article.date_bc}
  - marque            : ${article.marque}
  - code_fournisseur  : ${article.code_fournisseur}
  - numero_bc         : ${article.numero_bc}
  - score_initial     : ${article._score_initial}%
  - alerte_initiale   : ${article._alerte_initiale}
  - erp_candidates    :
${candidatesReadable}`;
}).join('\n\n' + '─'.repeat(50) + '\n\n');

return [{
  json: {
    nb_articles:      nbArticles,
    articles_readable: articlesReadable,
    articles_json:    articlesJson,
    // Conserver les données originales pour le parsing après LLM
    original_data:    dataArray
  }
}];

const output = items[0].json.stdout;
const result = JSON.parse(output);

// Retourner chaque fichier comme un item séparé avec le chemin complet formaté
return result.files.map(file => ({
  json: {
    page_number: file.page_number,
    file_name: file.file_name,
    file_path: file.file_path,
    // Nouveau champ avec le chemin formaté pour n8n
    formatted_path: `C:/hicham/data/document_pages/${file.file_name}`,
    total_pages: result.total_pages
  }
}));

