return $input.all();

const results = [];
for (const item of items) {
  const data = item.json.output;
  const bcs = (data.numero_bc || "")
    .split(/[-,]/)
    .map(s => s.trim())
    .filter(s => s.length > 0);

  const statut_bc = bcs.length > 1 ? "MULTIPLE_BC" : "UNIQUE_BC";

  for (const ligne of data.lignes || []) {
    for (const bc of bcs) {
      results.push({
        json: {
          type_document: data.type_document,
          numero_bl: data.numero_bl,
          date_bl: data.date_bl,
          numero_bc: bc,
          statut_bc: statut_bc,
          fournisseur_nom: data.fournisseur_nom,
          base_ht: data.base_ht,
          tva_montant: data.tva_montant,
          total_ttc: data.total_ttc,
          lignes: [ligne]
        }
      });
    }
  }
}
return results;

// Node Code n8n - Mode: "Run Once for All Items"

const items = $input.all();

// ── Regrouper les lignes par numero_bl ─
const blGroups = {};

for (const item of items) {
  const data = item.json.input;
  const bl = data.numero_bl;

  if (!bl || bl === 'undefined') continue; // ignorer les lignes sans BL

  if (!blGroups[bl]) {
    blGroups[bl] = {
      numero_bl: bl,
      numero_bc: data.POHNUM_0,
      code_fournisseur: data.BPSNUM_0,
      date_bc: data.ORDDAT_0,
      lignes: []
    };
  }

  blGroups[bl].lignes.push({
    designation_ocr:    data.designation_ocr,
    reference_ocr:      data.reference_ocr,
    reference_ocr_norm: data.reference_ocr_norm,
    quantite_ocr:       data.quantite_ocr,
    prix_unitaire_ocr:  data.prix_unitaire_ocr,
    montant_ht_ocr:      data.montant_ht_ocr,
    skip_numerique_reason: data.skip_numerique_reason,
    statut:              item.json.statut,
    score:                item.json.score,
    nb_bc_candidats:      item.json.nb_bc_candidats,
    bc_candidats:         item.json.bc_candidats
  });
}

// ── Construire un item Redis par BL ─
const toRedis = Object.values(blGroups).map(group => {
  const redisData = {
    numero_bl: group.numero_bl,
    numero_bc: group.numero_bc,
    code_fournisseur: group.code_fournisseur,
    date_bc: group.date_bc,
    nb_lignes_non_matchees: group.lignes.length,
    lignes: group.lignes,
    date_creation: new Date().toISOString(),
    statut_global: 'en_attente_resolution'
  };

  return {
    json: {
      redis_key: `bl_non_matched:${group.numero_bl}`,
      redis_value: JSON.stringify(redisData),
      redis_ttl: 300, // 24h — à ajuster selon besoin
      user_data: redisData
    }
  };
});

return toRedis;

// Node Code n8n - Mode: "Run Once for All Items"
// Ce node suppose que le node précédent a récupéré la valeur Redis (redis_value)

const items = $input.all();

const result = [];

for (const item of items) {
  // Le champ contenant le JSON stringifié récupéré de Redis
  // Adapter le nom du champ selon votre node Redis (ex: item.json.value, item.json.data, etc.)
  const rawValue = item.json.propertyName || item.json.redis_value || item.json.data;

  if (!rawValue) continue;

  let blData;
  try {
    blData = typeof rawValue === 'string' ? JSON.parse(rawValue) : rawValue;
  } catch (e) {
    // Log d'erreur de parsing, on continue avec l'item suivant
    result.push({
      json: {
        error: `Erreur de parsing JSON: ${e.message}`,
        raw: rawValue
      }
    });
    continue;
  }

  // ── Filtrer uniquement les lignes avec statut "non_matched" ─
  const lignesNonMatchees = (blData.lignes || []).filter(
    ligne => ligne.statut === 'non_matched'
  );

  // ── Créer un item n8n par ligne non matchée, avec le contexte du BL ─
  for (const ligne of lignesNonMatchees) {
    result.push({
      json: {
        // Contexte du BL/BC
        numero_bl: blData.numero_bl,
        numero_bc: blData.numero_bc,
        code_fournisseur: blData.code_fournisseur,
        date_bc: blData.date_bc,
        date_creation: blData.date_creation,
        statut_global: blData.statut_global,

        // Détails de la ligne non matchée
        designation_ocr: ligne.designation_ocr,
        reference_ocr: ligne.reference_ocr,
        reference_ocr_norm: ligne.reference_ocr_norm,
        quantite_ocr: ligne.quantite_ocr,
        prix_unitaire_ocr: ligne.prix_unitaire_ocr,
        montant_ht_ocr: ligne.montant_ht_ocr,
        skip_numerique_reason: ligne.skip_numerique_reason,
        statut: ligne.statut,
        score: ligne.score,
        nb_bc_candidats: ligne.nb_bc_candidats,
        bc_candidats: ligne.bc_candidats
      }
    });
  }
}

return result;
